// Function to validate return_url and prevent open redirect vulnerabilities
function validateReturnUrl(returnUrl) {
  const defaultUrl = '/';

  if (!returnUrl) {
    return defaultUrl;
  }

  try {
    // Only allow relative URLs or URLs from our own domain
    // This prevents open redirect attacks where an attacker could craft:
    // /auth/callback?return_url=https://evil-site.com
    const allowedHosts = [
      'localhost',
      'yourdomain.com',
      'www.yourdomain.com'
    ];

    // Check if it's a relative URL (starts with /)
    if (returnUrl.startsWith('/') && !returnUrl.startsWith('//')) {
      return returnUrl;
    }

    // If it's an absolute URL, validate the host
    const parsedUrl = new URL(returnUrl);
    if (allowedHosts.includes(parsedUrl.hostname)) {
      return returnUrl;
    }

    // If the URL doesn't pass validation, return default
    console.warn(`Blocked potentially malicious return_url: ${returnUrl}`);
    return defaultUrl;

  } catch (e) {
    // If URL parsing fails, return default
    return defaultUrl;
  }
}

